class Solution:
    def findKthNumber(self, n: int, k: int) -> int:
        cur = 1
        k -= 1
        while k > 0:
            step = 0
            first = cur
            last = cur + 1
            while first <= n:
                step += min(n + 1, last) - first
                first *= 10
                last *= 10
            if k >= step:
                k -= step
                cur += 1
            else:
                k -= 1
                cur *= 10
        return cur

